// グローバルポインタを「配列+オフセット」で初期化すると壊れるバグ。
// `int *p = a + 1;` / `int *p = &a[1];` で非ゼロオフセットがシンボル初期化子に
// 反映されず (init_symbol のみで offset を持たなかった)、誤アドレスを指していた。
// 修正: シンボル+バイトオフセットを解決し `.quad _sym + N` を出力する。
// 修正前: exit=139 等 (garbage)
// 期待: exit=42
int a[4] = {10, 20, 30, 42};
int *p = a + 1;        // &a[1]
int *q = &a[3];        // &a[3]
int main(void) {
    return (*p == 20 && q[0] == 42) ? *q : 0;   // 42
}
